def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Comprehensive caching
    hv_cache: Dict[frozenset, float] = {}
    contrib_cache: Dict[Tuple[frozenset, int], float] = {}

    def compute_hv(indices: Set[int]) -> float:
        """Compute hypervolume for a set of indices"""
        if not indices:
            return 0.0

        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]

        selected = points[list(indices)]
        hv_obj = pg.hypervolume(selected)
        hv = hv_obj.compute(reference_point)
        hv_cache[key] = hv
        return hv

    def marginal_contribution(S: Set[int], p: int) -> float:
        """Compute marginal contribution of point p to set S"""
        key = (frozenset(S), p)
        if key in contrib_cache:
            return contrib_cache[key]

        if p in S:
            S_without = S - {p}
            contrib = compute_hv(S) - compute_hv(S_without)
        else:
            S_with = S | {p}
            contrib = compute_hv(S_with) - compute_hv(S)

        contrib_cache[key] = contrib
        return contrib

    # Phase 1: Fast greedy initialization with incremental updates
    def greedy_initialization() -> Set[int]:
        """Greedy construction using marginal contributions with caching"""
        current = set()
        contributions = [0.0] * n

        # Initialize contributions for empty set
        for idx in range(n):
            contributions[idx] = marginal_contribution(set(), idx)

        for _ in range(k):
            # Find point with maximum contribution
            best_idx = -1
            best_contrib = -float('inf')

            for idx in range(n):
                if idx in current:
                    continue
                if contributions[idx] > best_contrib:
                    best_contrib = contributions[idx]
                    best_idx = idx

            if best_idx != -1:
                current.add(best_idx)

                # Update contributions for remaining points
                for idx in range(n):
                    if idx not in current:
                        contributions[idx] = marginal_contribution(current, idx)

        return current

    # Phase 2: Contribution-guided evolutionary search with Pareto archive
    pop_size = 20
    archive_size = 15
    max_generations = 40

    # Initialize population with greedy solution
    greedy_sol = greedy_initialization()
    population = [greedy_sol]

    # Add diverse solutions
    for _ in range(pop_size - 1):
        if random.random() < 0.6:
            # Mutation of greedy solution
            sol = set(greedy_sol)
            mutation_rate = min(0.4, 1.0 / max(1, len(sol)))

            # Remove low-contribution points
            if len(sol) > 1:
                for idx in list(sol):
                    if random.random() < mutation_rate:
                        sol.remove(idx)

            # Add high-contribution points
            while len(sol) < k and len(sol) < n:
                available = set(range(n)) - sol
                if not available:
                    break

                # Sample candidates for efficiency
                candidates = random.sample(list(available), min(10, len(available)))
                best_idx = None
                best_contrib = -float('inf')

                for idx in candidates:
                    contrib = marginal_contribution(sol, idx)
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx

                if best_idx is not None:
                    sol.add(best_idx)
        else:
            # Random solution near size k
            size = random.randint(max(1, k-2), min(k+2, n))
            sol = set(random.sample(range(n), size))

        # Adjust to size k using contribution guidance
        while len(sol) > k:
            # Remove worst contributor
            worst_idx = None
            worst_contrib = float('inf')

            for idx in sol:
                contrib = marginal_contribution(sol - {idx}, idx)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx

            if worst_idx is not None:
                sol.remove(worst_idx)

        while len(sol) < k and len(sol) < n:
            # Add best contributor
            available = set(range(n)) - sol
            if not available:
                break

            best_idx = None
            best_contrib = -float('inf')

            for idx in available:
                contrib = marginal_contribution(sol, idx)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx

            if best_idx is not None:
                sol.add(best_idx)

        population.append(sol)

    # Initialize Pareto archive
    archive: List[Tuple[Set[int], int, float]] = []

    def update_archive(solution: Set[int], size: int, hv: float):
        """Update Pareto archive with non-dominated solutions"""
        nonlocal archive

        # Check if dominated by existing archive members
        dominated = False
        to_remove = []

        for i, (a_sol, a_size, a_hv) in enumerate(archive):
            size_diff_sol = abs(size - k)
            size_diff_arch = abs(a_size - k)

            # Check dominance
            if size_diff_arch <= size_diff_sol and a_hv >= hv and (size_diff_arch < size_diff_sol or a_hv > hv):
                dominated = True
                break

            # If new solution dominates archive member
            if size_diff_sol <= size_diff_arch and hv >= a_hv and (size_diff_sol < size_diff_arch or hv > a_hv):
                to_remove.append(i)

        if not dominated:
            # Remove dominated solutions
            for i in sorted(to_remove, reverse=True):
                archive.pop(i)

            # Add new solution
            archive.append((solution.copy(), size, hv))

            # Keep archive bounded
            if len(archive) > archive_size:
                archive.sort(key=lambda x: (abs(x[1] - k), -x[2]))
                archive = archive[:archive_size]

    # Evaluate initial population and update archive
    for sol in population:
        size = len(sol)
        hv = compute_hv(sol)
        update_archive(sol, size, hv)

    # Evolutionary search
    for gen in range(max_generations):
        # Generate offspring using deterministic operators
        offspring = []

        for _ in range(pop_size // 2):
            # Tournament selection from archive
            if len(archive) >= 2:
                idx1, idx2 = random.sample(range(len(archive)), 2)
                parent1 = archive[idx1][0]
                parent2 = archive[idx2][0]
            else:
                parent1 = random.choice(population)
                parent2 = random.choice(population)

            # Crossover: take union, then adjust to size k
            child = parent1 | parent2

            # Contribution-guided size adjustment
            while len(child) > k:
                # Remove worst contributor
                worst_idx = None
                worst_contrib = float('inf')

                for idx in child:
                    contrib = marginal_contribution(child - {idx}, idx)
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx

                if worst_idx is not None:
                    child.remove(worst_idx)

            while len(child) < k and len(child) < n:
                # Add best contributor
                available = set(range(n)) - child
                if not available:
                    break

                best_idx = None
                best_contrib = -float('inf')

                for idx in available:
                    contrib = marginal_contribution(child, idx)
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx

                if best_idx is not None:
                    child.add(best_idx)

            # Deterministic mutation based on size deviation
            size_dev = abs(len(child) - k)
            mutation_rate = min(0.3, 1.0 / (1 + size_dev))

            if random.random() < mutation_rate and len(child) > 1:
                # Remove worst contributor
                worst_idx = None
                worst_contrib = float('inf')

                for idx in child:
                    contrib = marginal_contribution(child - {idx}, idx)
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx

                if worst_idx is not None:
                    child.remove(worst_idx)

            if random.random() < mutation_rate and len(child) < n:
                # Add best contributor
                available = set(range(n)) - child
                if available:
                    best_idx = None
                    best_contrib = -float('inf')

                    for idx in available:
                        contrib = marginal_contribution(child, idx)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_idx = idx

                    if best_idx is not None:
                        child.add(best_idx)

            # Ensure size constraint
            while len(child) > k:
                worst_idx = None
                worst_contrib = float('inf')

                for idx in child:
                    contrib = marginal_contribution(child - {idx}, idx)
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx

                if worst_idx is not None:
                    child.remove(worst_idx)

            while len(child) < k and len(child) < n:
                available = set(range(n)) - child
                if available:
                    best_idx = None
                    best_contrib = -float('inf')

                    for idx in available:
                        contrib = marginal_contribution(child, idx)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_idx = idx

                    if best_idx is not None:
                        child.add(best_idx)

            offspring.append(child)

        # Evaluate offspring and update archive
        for child in offspring:
            size = len(child)
            hv = compute_hv(child)
            update_archive(child, size, hv)

        # Update population from archive
        if archive:
            population = [sol for sol, _, _ in archive]
            if len(population) > pop_size:
                population = population[:pop_size]

    # Phase 3: Efficient local refinement
    def local_refinement(S: Set[int]) -> Set[int]:
        """Contribution-guided local search with efficient swap evaluation"""
        current = S.copy()
        current_hv = compute_hv(current)
        improved = True
        iterations = 0

        while improved and iterations < 15:
            improved = False
            iterations += 1

            # Precompute contributions for current set
            in_contrib = {}
            for idx in current:
                in_contrib[idx] = marginal_contribution(current - {idx}, idx)

            # Find worst point in current set
            worst_idx = min(in_contrib.items(), key=lambda x: x[1])[0]
            worst_contrib = in_contrib[worst_idx]

            # Find best replacement
            best_idx = None
            best_gain = -float('inf')

            for idx in range(n):
                if idx in current:
                    continue

                # Fast contribution comparison
                contrib = marginal_contribution(current - {worst_idx}, idx)
                gain = contrib - worst_contrib

                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx

            # Perform swap if beneficial
            if best_idx is not None and best_gain > 1e-10:
                new_set = (current - {worst_idx}) | {best_idx}
                new_hv = compute_hv(new_set)

                if new_hv > current_hv:
                    current = new_set
                    current_hv = new_hv
                    improved = True

        return current

    # Find best solution from archive
    best_solution = None
    best_hv = -float('inf')

    for sol, size, hv in archive:
        if size == k and hv > best_hv:
            best_hv = hv
            best_solution = sol

    # If no exact size k solution, use closest
    if best_solution is None:
        archive.sort(key=lambda x: (abs(x[1] - k), -x[2]))
        best_solution = archive[0][0].copy()

    # Final size adjustment using contribution guidance
    while len(best_solution) > k:
        worst_idx = None
        worst_contrib = float('inf')

        for idx in best_solution:
            contrib = marginal_contribution(best_solution - {idx}, idx)
            if contrib < worst_contrib:
                worst_contrib = contrib
                worst_idx = idx

        if worst_idx is not None:
            best_solution.remove(worst_idx)

    while len(best_solution) < k:
        best_idx = None
        best_contrib = -float('inf')

        for idx in range(n):
            if idx in best_solution:
                continue

            contrib = marginal_contribution(best_solution, idx)
            if contrib > best_contrib:
                best_contrib = contrib
                best_idx = idx

        if best_idx is not None:
            best_solution.add(best_idx)

    # Apply final refinement
    final_solution = local_refinement(best_solution)

    return points[list(final_solution)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume cache
    hv_cache: Dict[frozenset, float] = {}

    def compute_hv(indices_set: Set[int]) -> float:
        """Compute hypervolume for a set of indices"""
        if not indices_set:
            return 0.0

        key = frozenset(indices_set)
        if key in hv_cache:
            return hv_cache[key]

        selected = points[list(indices_set)]
        hv_obj = pg.hypervolume(selected)
        hv = hv_obj.compute(reference_point)
        hv_cache[key] = hv
        return hv

    def marginal_contribution(S: Set[int], p: int) -> float:
        """Compute marginal contribution of point p to set S"""
        if p in S:
            S_without = S - {p}
            return compute_hv(S) - compute_hv(S_without)
        else:
            S_with = S | {p}
            return compute_hv(S_with) - compute_hv(S)

    # Pareto archive: store solutions of different sizes
    pareto_archive: Dict[int, Set[int]] = {}

    # 1. Greedy initialization
    def greedy_initialization() -> Set[int]:
        """Fast greedy construction using marginal contributions"""
        current_set = set()

        for _ in range(k):
            best_idx = -1
            best_contrib = -float('inf')

            for idx in range(n):
                if idx in current_set:
                    continue
                contrib = marginal_contribution(current_set, idx)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx

            if best_idx != -1:
                current_set.add(best_idx)

        pareto_archive[k] = current_set
        return current_set

    # 2. Evolutionary search with adaptive mutation
    def evolutionary_search(base_solution: Set[int], generations: int = 15) -> Set[int]:
        """Evolutionary search with size-biased mutation"""
        population_size = 10
        population: List[Set[int]] = [base_solution.copy()]
        population_hv = [compute_hv(base_solution)]

        # Initialize population with mutated solutions
        for i in range(population_size - 1):
            mutated = base_solution.copy()

            # Adaptive mutation rate based on size deviation
            current_size = len(mutated)
            size_deviation = abs(current_size - k) / k
            mutation_rate = 0.4 * (1 - size_deviation)  # Higher rate when size is far from k

            if random.random() < mutation_rate:
                # Biased mutation: remove worst, add best by contribution
                if len(mutated) > 0:
                    # Remove worst point
                    worst_contrib = float('inf')
                    worst_idx = None
                    for idx in mutated:
                        contrib = marginal_contribution(mutated - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        mutated.remove(worst_idx)

                # Add best point
                best_contrib = -float('inf')
                best_idx = None
                for idx in range(n):
                    if idx not in mutated:
                        contrib = marginal_contribution(mutated, idx)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_idx = idx

                if best_idx is not None:
                    mutated.add(best_idx)

            # Ensure size is exactly k
            while len(mutated) > k:
                # Remove point with smallest contribution
                smallest_contrib = float('inf')
                remove_idx = None
                for idx in mutated:
                    contrib = marginal_contribution(mutated - {idx}, idx)
                    if contrib < smallest_contrib:
                        smallest_contrib = contrib
                        remove_idx = idx

                if remove_idx is not None:
                    mutated.remove(remove_idx)

            while len(mutated) < k:
                # Add point with largest contribution
                largest_contrib = -float('inf')
                add_idx = None
                for idx in range(n):
                    if idx not in mutated:
                        contrib = marginal_contribution(mutated, idx)
                        if contrib > largest_contrib:
                            largest_contrib = contrib
                            add_idx = idx

                if add_idx is not None:
                    mutated.add(add_idx)

            population.append(mutated)
            population_hv.append(compute_hv(mutated))

        # Evolutionary generations
        for gen in range(generations):
            # Tournament selection
            tournament_indices = random.sample(range(population_size), 3)
            parent_idx = tournament_indices[0]
            for idx in tournament_indices:
                if population_hv[idx] > population_hv[parent_idx]:
                    parent_idx = idx

            parent = population[parent_idx]

            # Create offspring with size-biased mutation
            offspring = parent.copy()
            current_size = len(offspring)
            size_deviation = abs(current_size - k) / k
            mutation_rate = 0.3 * (1 - size_deviation)

            if random.random() < mutation_rate:
                # Contribution-guided swap
                if len(offspring) > 0:
                    # Remove worst
                    worst_contrib = float('inf')
                    worst_idx = None
                    for idx in offspring:
                        contrib = marginal_contribution(offspring - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        offspring.remove(worst_idx)

                    # Add best
                    best_contrib = -float('inf')
                    best_idx = None
                    for idx in range(n):
                        if idx not in offspring:
                            contrib = marginal_contribution(offspring, idx)
                            if contrib > best_contrib:
                                best_contrib = contrib
                                best_idx = idx

                    if best_idx is not None:
                        offspring.add(best_idx)

            # Size correction
            while len(offspring) > k:
                smallest_contrib = float('inf')
                remove_idx = None
                for idx in offspring:
                    contrib = marginal_contribution(offspring - {idx}, idx)
                    if contrib < smallest_contrib:
                        smallest_contrib = contrib
                        remove_idx = idx

                if remove_idx is not None:
                    offspring.remove(remove_idx)

            while len(offspring) < k:
                largest_contrib = -float('inf')
                add_idx = None
                for idx in range(n):
                    if idx not in offspring:
                        contrib = marginal_contribution(offspring, idx)
                        if contrib > largest_contrib:
                            largest_contrib = contrib
                            add_idx = idx

                if add_idx is not None:
                    offspring.add(add_idx)

            offspring_hv = compute_hv(offspring)

            # Replace worst in population
            worst_idx = np.argmin(population_hv)
            if offspring_hv > population_hv[worst_idx]:
                population[worst_idx] = offspring
                population_hv[worst_idx] = offspring_hv

            # Update Pareto archive
            if offspring_hv > compute_hv(pareto_archive.get(k, set())):
                pareto_archive[k] = offspring

        # Return best solution
        best_idx = np.argmax(population_hv)
        return population[best_idx]

    # 3. Contribution-guided local swap refinement
    def local_swap_refinement(solution: Set[int], max_iter: int = 20) -> Set[int]:
        """Local refinement using contribution-guided swaps"""
        current_set = solution.copy()
        current_hv = compute_hv(current_set)

        for _ in range(max_iter):
            improved = False

            # Try swapping worst point with best external point
            worst_contrib = float('inf')
            worst_idx = None
            for idx in current_set:
                contrib = marginal_contribution(current_set - {idx}, idx)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx

            if worst_idx is None:
                break

            best_external_contrib = -float('inf')
            best_external_idx = None
            for idx in range(n):
                if idx not in current_set:
                    contrib = marginal_contribution(current_set - {worst_idx}, idx)
                    if contrib > best_external_contrib:
                        best_external_contrib = contrib
                        best_external_idx = idx

            if best_external_idx is not None:
                new_set = (current_set - {worst_idx}) | {best_external_idx}
                new_hv = compute_hv(new_set)

                if new_hv > current_hv:
                    current_set = new_set
                    current_hv = new_hv
                    improved = True

            if not improved:
                break

        return current_set

    # Main algorithm flow
    greedy_solution = greedy_initialization()
    evolved_solution = evolutionary_search(greedy_solution)
    final_solution = local_swap_refinement(evolved_solution)

    return points[list(final_solution)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume cache
    hv_cache = {}

    def compute_hv(indices: Set[int]) -> float:
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        data = points[list(indices), :]
        hv = pg.hypervolume(data)
        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    # 1. Greedy initialization with caching
    def greedy_initialization() -> Set[int]:
        current = set()
        for _ in range(k):
            best_gain = -float('inf')
            best_idx = None
            for idx in range(n):
                if idx in current:
                    continue
                temp = current | {idx}
                gain = compute_hv(temp) - compute_hv(current)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            if best_idx is not None:
                current.add(best_idx)
        return current

    # 2. Initialize population with greedy and variations
    population = []
    pop_size = 30
    greedy_sol = greedy_initialization()
    population.append((greedy_sol, compute_hv(greedy_sol), len(greedy_sol)))

    for _ in range(pop_size - 1):
        if random.random() < 0.7:
            sol = set(greedy_sol)
            mutation_rate = min(0.3, 1.0 / (2 * k))
            # Remove some points
            if len(sol) > 1:
                for idx in list(sol):
                    if random.random() < mutation_rate:
                        sol.remove(idx)
            # Add points with high contribution
            while len(sol) < k and len(sol) < n:
                available = set(range(n)) - sol
                if not available:
                    break
                best_gain = -float('inf')
                best_idx = None
                candidates = random.sample(list(available), min(10, len(available)))
                for idx in candidates:
                    temp = sol | {idx}
                    gain = compute_hv(temp) - compute_hv(sol)
                    if gain > best_gain:
                        best_gain = gain
                        best_idx = idx
                if best_idx is not None:
                    sol.add(best_idx)
        else:
            size = random.randint(max(1, k-2), min(k+2, n))
            sol = set(random.sample(range(n), size))

        # Adjust size to near k
        while len(sol) > k:
            worst_idx = None
            worst_contrib = float('inf')
            for idx in list(sol):
                temp = sol - {idx}
                contrib = compute_hv(sol) - compute_hv(temp)
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx
            if worst_idx is not None:
                sol.remove(worst_idx)

        while len(sol) < k and len(sol) < n:
            available = set(range(n)) - sol
            if available:
                best_idx = None
                best_gain = -float('inf')
                candidates = random.sample(list(available), min(15, len(available)))
                for idx in candidates:
                    temp = sol | {idx}
                    gain = compute_hv(temp) - compute_hv(sol)
                    if gain > best_gain:
                        best_gain = gain
                        best_idx = idx
                if best_idx is not None:
                    sol.add(best_idx)

        population.append((sol, compute_hv(sol), len(sol)))

    # 3. Pareto archive maintenance
    archive = []
    archive_max = 30
    target_size = k

    def update_archive(solution: Set[int], size: int, hv: float):
        nonlocal archive
        dominated = False
        to_remove = []
        for i, (a_sol, a_size, a_hv) in enumerate(archive):
            if a_size == size and abs(a_hv - hv) < 1e-9:
                dominated = True
                break
            size_diff_curr = abs(size - target_size)
            size_diff_arch = abs(a_size - target_size)
            if size_diff_curr <= size_diff_arch and hv >= a_hv and (size_diff_curr < size_diff_arch or hv > a_hv):
                to_remove.append(i)
            elif size_diff_arch <= size_diff_curr and a_hv >= hv and (size_diff_arch < size_diff_curr or a_hv > hv):
                dominated = True
                break
        if not dominated:
            for i in sorted(to_remove, reverse=True):
                archive.pop(i)
            archive.append((solution.copy(), size, hv))
        if len(archive) > archive_max:
            archive.sort(key=lambda x: (abs(x[1] - target_size), -x[2]))
