        contributions.sort()
        final_indices = [idx for _, idx in contributions[:k]]
    elif len(final_indices) < k:
        # Add largest contributors
        current = set(final_indices)
        for _ in range(k - len(final_indices)):
            best_idx = None
            best_gain = -float('inf')
            available = set(range(n)) - current
            for idx in available:
                temp = current | {idx}
                gain = compute_hv(temp) - compute_hv(current)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            if best_idx is not None:
                current.add(best_idx)
                final_indices.append(best_idx)

    return points[final_indices, :]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Comprehensive caching
    hv_cache: Dict[frozenset, float] = {}
    contrib_cache: Dict[Tuple[frozenset, int], float] = {}

    def compute_hv(indices_set: Set[int]) -> float:
        """Compute hypervolume for a set of indices"""
        if not indices_set:
            return 0.0

        key = frozenset(indices_set)
        if key in hv_cache:
            return hv_cache[key]

        selected = points[list(indices_set)]
        hv_obj = pg.hypervolume(selected)
        hv = hv_obj.compute(reference_point)
        hv_cache[key] = hv
        return hv

    def marginal_contribution(S: Set[int], p: int) -> float:
        """Compute marginal contribution of point p to set S"""
        key = (frozenset(S), p)
        if key in contrib_cache:
            return contrib_cache[key]

        if p in S:
            S_without = S - {p}
            contrib = compute_hv(S) - compute_hv(S_without)
        else:
            S_with = S | {p}
            contrib = compute_hv(S_with) - compute_hv(S)

        contrib_cache[key] = contrib
        return contrib

    # Phase 1: Greedy seeding
    def greedy_seeding() -> Set[int]:
        """Deterministic greedy construction"""
        current_set = set()

        for _ in range(k):
            best_idx = -1
            best_contrib = -float('inf')

            for idx in range(n):
                if idx in current_set:
                    continue
                contrib = marginal_contribution(current_set, idx)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx

            if best_idx != -1:
                current_set.add(best_idx)

        return current_set

    # Pareto archive
    class ParetoArchive:
        def __init__(self):
            self.archive: List[Tuple[Set[int], float, int]] = []  # (solution, hv, size)

        def add(self, solution: Set[int]):
            hv = compute_hv(solution)
            size = len(solution)

            # Check dominance
            to_remove = []
            for i, (sol, arch_hv, arch_size) in enumerate(self.archive):
                if arch_size == size and arch_hv >= hv:
                    return  # Dominated
                if size == arch_size and hv > arch_hv:
                    to_remove.append(i)
                elif size > arch_size and hv >= arch_hv:
                    to_remove.append(i)
                elif size < arch_size and hv <= arch_hv:
                    to_remove.append(i)

            # Remove dominated
            for i in sorted(to_remove, reverse=True):
                del self.archive[i]

            self.archive.append((solution.copy(), hv, size))

        def get_best_size_k(self) -> Set[int]:
            """Get best solution with size k"""
            best_sol = None
            best_hv = -float('inf')

            for sol, hv, size in self.archive:
                if size == k and hv > best_hv:
                    best_hv = hv
                    best_sol = sol

            if best_sol is None:
                # Find closest size
                for sol, hv, size in self.archive:
                    if abs(size - k) <= 2 and hv > best_hv:
                        best_hv = hv
                        best_sol = sol

            return best_sol.copy() if best_sol else set()

    archive = ParetoArchive()

    # Phase 2: Evolutionary search with size-adaptive mutation
    def evolutionary_search(initial_solution: Set[int], generations: int = 20) -> Set[int]:
        """Evolutionary search with deterministic operators"""
        population_size = 15
        population = [initial_solution.copy()]
        archive.add(initial_solution)

        # Initialize population with size variations
        for i in range(1, population_size):
            sol = initial_solution.copy()
            current_size = len(sol)

            # Size-adaptive mutation rate
            size_diff = abs(current_size - k)
            mutation_rate = 0.3 + 0.4 * (size_diff / max(k, n - k))

            if random.random() < mutation_rate:
                if current_size > k and len(sol) > 0:
                    # Remove worst point deterministically
                    worst_contrib = float('inf')
                    worst_idx = None

                    for idx in sol:
                        contrib = marginal_contribution(sol - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        sol.remove(worst_idx)

                elif current_size < k and len(sol) < n:
                    # Add best point deterministically
                    best_contrib = -float('inf')
                    best_idx = None

                    for idx in range(n):
                        if idx in sol:
                            continue
                        contrib = marginal_contribution(sol, idx)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_idx = idx

                    if best_idx is not None:
                        sol.add(best_idx)

                else:
                    # Swap: remove worst, add best
                    if len(sol) > 0:
                        # Find worst in current set
                        worst_contrib = float('inf')
                        worst_idx = None

                        for idx in sol:
                            contrib = marginal_contribution(sol - {idx}, idx)
                            if contrib < worst_contrib:
                                worst_contrib = contrib
                                worst_idx = idx

                        if worst_idx is not None:
                            sol.remove(worst_idx)

                            # Find best outside set
                            best_contrib = -float('inf')
                            best_idx = None

                            for idx in range(n):
                                if idx in sol:
                                    continue
                                contrib = marginal_contribution(sol, idx)
                                if contrib > best_contrib:
                                    best_contrib = contrib
                                    best_idx = idx

                            if best_idx is not None:
                                sol.add(best_idx)

            # Ensure size is reasonable
            while len(sol) > k + 2:
                # Remove worst
                worst_contrib = float('inf')
                worst_idx = None

                for idx in sol:
                    contrib = marginal_contribution(sol - {idx}, idx)
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx

                if worst_idx is not None:
                    sol.remove(worst_idx)

            while len(sol) < max(1, k - 2):
                # Add best
                best_contrib = -float('inf')
                best_idx = None

                for idx in range(n):
                    if idx in sol:
                        continue
                    contrib = marginal_contribution(sol, idx)
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx

                if best_idx is not None:
                    sol.add(best_idx)

            population.append(sol)
            archive.add(sol)

        # Evolution
        for gen in range(generations):
            # Deterministic selection: top 3 by HV
            population.sort(key=lambda s: compute_hv(s), reverse=True)
            parents = population[:3]

            # Create offspring from best parent
            parent = parents[0].copy()
            current_size = len(parent)

            # Adaptive mutation based on size deviation
            size_diff = abs(current_size - k)
            mutation_strength = 0.4 * (1.0 - gen / generations) + 0.1 * (size_diff / k)

            if random.random() < mutation_strength:
                if current_size > k:
                    # Remove worst
                    worst_contrib = float('inf')
                    worst_idx = None

                    for idx in parent:
                        contrib = marginal_contribution(parent - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        parent.remove(worst_idx)

                elif current_size < k:
                    # Add best
                    best_contrib = -float('inf')
                    best_idx = None

                    for idx in range(n):
                        if idx in parent:
                            continue
                        contrib = marginal_contribution(parent, idx)
                        if contrib > best_contrib:
                            best_contrib = contrib
                            best_idx = idx

                    if best_idx is not None:
                        parent.add(best_idx)

                else:
                    # Swap operation
                    if len(parent) > 0:
                        # Remove worst
                        worst_contrib = float('inf')
                        worst_idx = None

                        for idx in parent:
                            contrib = marginal_contribution(parent - {idx}, idx)
                            if contrib < worst_contrib:
                                worst_contrib = contrib
                                worst_idx = idx

                        if worst_idx is not None:
                            parent.remove(worst_idx)

                            # Add best
                            best_contrib = -float('inf')
                            best_idx = None

                            for idx in range(n):
                                if idx in parent:
                                    continue
                                contrib = marginal_contribution(parent, idx)
                                if contrib > best_contrib:
                                    best_contrib = contrib
                                    best_idx = idx

                            if best_idx is not None:
                                parent.add(best_idx)

            # Ensure size constraint
            while len(parent) > k:
                worst_contrib = float('inf')
                worst_idx = None

                for idx in parent:
                    contrib = marginal_contribution(parent - {idx}, idx)
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx

                if worst_idx is not None:
                    parent.remove(worst_idx)

            while len(parent) < k:
                best_contrib = -float('inf')
                best_idx = None

                for idx in range(n):
                    if idx in parent:
                        continue
                    contrib = marginal_contribution(parent, idx)
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx

                if best_idx is not None:
                    parent.add(best_idx)

            # Replace worst in population
            population.sort(key=lambda s: compute_hv(s))
            offspring_hv = compute_hv(parent)

            if offspring_hv > compute_hv(population[0]):
                population[0] = parent
                archive.add(parent)

        # Return best solution from population
        population.sort(key=lambda s: compute_hv(s), reverse=True)
        return population[0]

    # Phase 3: Contribution-guided local refinement
    def local_refinement(solution: Set[int], max_iter: int = 15) -> Set[int]:
        """Deterministic local search using contribution-guided swaps"""
        current_set = solution.copy()
        current_hv = compute_hv(current_set)

        for _ in range(max_iter):
            improved = False

            # Evaluate all possible swaps
            best_swap = None
            best_delta = 0.0

            # Points in current set sorted by contribution (worst first)
            internal_points = list(current_set)
            internal_points.sort(key=lambda idx: marginal_contribution(current_set - {idx}, idx))

            # Points outside current set sorted by potential contribution (best first)
            external_points = [idx for idx in range(n) if idx not in current_set]
            external_points.sort(key=lambda idx: marginal_contribution(current_set, idx), reverse=True)

            # Try top candidates
            for remove_idx in internal_points[:3]:  # Worst 3 points
                temp_set = current_set - {remove_idx}

                for add_idx in external_points[:3]:  # Best 3 external points
                    new_set = temp_set | {add_idx}
                    new_hv = compute_hv(new_set)
                    delta = new_hv - current_hv

                    if delta > best_delta:
                        best_delta = delta
                        best_swap = (remove_idx, add_idx)

            if best_swap is not None and best_delta > 1e-10:
                remove_idx, add_idx = best_swap
                current_set.remove(remove_idx)
                current_set.add(add_idx)
                current_hv += best_delta
                improved = True

            if not improved:
                break

        return current_set

    # Main algorithm flow
    # 1. Greedy seeding
    greedy_solution = greedy_seeding()
    archive.add(greedy_solution)

    # 2. Evolutionary search with Pareto archiving
    evolutionary_solution = evolutionary_search(greedy_solution)
    archive.add(evolutionary_solution)

    # 3. Get best size-k solution from archive
    best_solution = archive.get_best_size_k()

    # 4. Final local refinement
    final_solution = local_refinement(best_solution)

    return points[list(final_solution)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, d = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume computation setup
    try:
        import pygmo as pg
        hv_calc = pg.hypervolume
    except ImportError:
        raise ImportError("pygmo is required for hypervolume computation")

    # Cache for hypervolume values
    hv_cache: Dict[Tuple[int, ...], float] = {}

    def compute_hv(indices: Set[int]) -> float:
        """Compute hypervolume of a subset given by indices."""
        key = tuple(sorted(indices))
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv = 0.0
        else:
            subset = points[list(indices)]
            hv_obj = hv_calc(subset)
            hv = hv_obj.compute(reference_point)
        hv_cache[key] = hv
        return hv

    def marginal_contribution(S: Set[int], p: int) -> float:
        """Compute marginal contribution of point p to set S."""
        if p in S:
            S_without = S - {p}
            return compute_hv(S) - compute_hv(S_without)
        else:
            S_with = S | {p}
            return compute_hv(S_with) - compute_hv(S)

    # Phase 1: Greedy construction
    def greedy_construction() -> Set[int]:
        """Construct initial solution using greedy algorithm."""
        current = set()
        for _ in range(k):
            best_idx = -1
            best_contrib = -float('inf')
            for idx in range(n):
                if idx in current:
                    continue
                contrib = marginal_contribution(current, idx)
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx
            if best_idx != -1:
                current.add(best_idx)
        return current

    # Phase 2: Hill climbing local search
    def hill_climbing(S: Set[int], max_iter: int = 50) -> Set[int]:
        """Improve solution using hill climbing with swap moves."""
        current = S.copy()
        current_hv = compute_hv(current)
        unchanged = 0

        for _ in range(max_iter):
            improved = False

            # Evaluate all possible swaps
            for idx_in in list(current):
                for idx_out in range(n):
                    if idx_out in current:
                        continue

                    # Try swap
                    new_set = (current - {idx_in}) | {idx_out}
                    new_hv = compute_hv(new_set)

                    if new_hv > current_hv:
                        current = new_set
                        current_hv = new_hv
                        improved = True
                        break

                if improved:
                    break

            if not improved:
                unchanged += 1
                if unchanged >= 3:
                    break
            else:
                unchanged = 0

        return current

    # Phase 3: Iterated local search
    def iterated_local_search(initial_solution: Set[int], iterations: int = 30) -> Set[int]:
        """Perform iterated local search with adaptive perturbation."""
        best_solution = initial_solution.copy()
        best_hv = compute_hv(best_solution)
        current_solution = initial_solution.copy()
        current_hv = best_hv

        # Adaptive perturbation strength
        perturbation_strength = max(1, k // 4)

        for it in range(iterations):
            # Perturbation: random walk
            perturbed = current_solution.copy()

            # Determine number of perturbations based on iteration
            num_perturb = perturbation_strength
            if it > iterations // 2:
                num_perturb = max(1, perturbation_strength // 2)

            for _ in range(num_perturb):
                if random.random() < 0.5 and len(perturbed) > 1:
                    # Remove a random point
                    to_remove = random.choice(list(perturbed))
                    perturbed.remove(to_remove)

                    # Add a random point if below k
                    if len(perturbed) < k:
                        available = set(range(n)) - perturbed
                        if available:
                            to_add = random.choice(list(available))
                            perturbed.add(to_add)
                else:
                    # Swap a random point
                    if perturbed:
                        to_remove = random.choice(list(perturbed))
                        perturbed.remove(to_remove)
                        available = set(range(n)) - perturbed
                        if available:
                            to_add = random.choice(list(available))
                            perturbed.add(to_add)

            # Ensure size is exactly k
            while len(perturbed) > k:
                # Remove worst point by contribution
                worst_contrib = float('inf')
                worst_idx = None
                for idx in perturbed:
                    contrib = marginal_contribution(perturbed - {idx}, idx)
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_idx = idx
                if worst_idx is not None:
                    perturbed.remove(worst_idx)

            while len(perturbed) < k:
                # Add best point by contribution
                available = set(range(n)) - perturbed
                if not available:
                    break
                best_contrib = -float('inf')
                best_idx = None
                for idx in available:
                    contrib = marginal_contribution(perturbed, idx)
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx
                if best_idx is not None:
                    perturbed.add(best_idx)

            # Local search on perturbed solution
            improved_solution = hill_climbing(perturbed, max_iter=20)
            improved_hv = compute_hv(improved_solution)

            # Acceptance criterion
            if improved_hv > current_hv:
                current_solution = improved_solution
                current_hv = improved_hv

                if improved_hv > best_hv:
                    best_solution = improved_solution.copy()
                    best_hv = improved_hv
            elif random.random() < math.exp((improved_hv - current_hv) / (current_hv + 1e-10) * (iterations - it) / iterations):
                # Probabilistic acceptance (decreasing over time)
                current_solution = improved_solution
                current_hv = improved_hv

            # Adjust perturbation strength
            if it % 5 == 0:
                if current_hv == best_hv:
                    # Stagnation - increase exploration
                    perturbation_strength = min(k // 2, perturbation_strength + 1)
                else:
                    # Progress - focus exploitation
                    perturbation_strength = max(1, perturbation_strength - 1)

        return best_solution

    # Phase 4: Final refinement
    def final_refinement(S: Set[int]) -> Set[int]:
        """Final intensive local search."""
        best = S.copy()
        best_hv = compute_hv(best)

        # Try multiple restarts
        for restart in range(3):
            current = best.copy()

            # Shake the solution
            if len(current) > 2:
                # Remove and add random points
                num_shake = min(3, k // 3)
                for _ in range(num_shake):
                    if current:
                        to_remove = random.choice(list(current))
                        current.remove(to_remove)
                    available = set(range(n)) - current
                    if available:
                        to_add = random.choice(list(available))
                        current.add(to_add)

            # Ensure size k
            while len(current) > k:
                # Remove by smallest contribution
                contributions = [(idx, marginal_contribution(current - {idx}, idx)) for idx in current]
                contributions.sort(key=lambda x: x[1])
                current.remove(contributions[0][0])

            while len(current) < k:
                available = set(range(n)) - current
                if not available:
                    break
                # Add by largest contribution
                contributions = [(idx, marginal_contribution(current, idx)) for idx in available]
                contributions.sort(key=lambda x: x[1], reverse=True)
                current.add(contributions[0][0])

            # Intensive hill climbing
            current = hill_climbing(current, max_iter=100)
            current_hv = compute_hv(current)

            if current_hv > best_hv:
                best = current.copy()
                best_hv = current_hv

        return best

    # Execute algorithm
    initial = greedy_construction()
    evolved = iterated_local_search(initial)
    final = final_refinement(evolved)

    # Return selected points
    return points[list(final)]
